/// The Yettragrammaton: R.W.Ϝ.Y. — sovereign identity seed for all ledger signing
pub const YETTRAGRAMMATON: &str = "R.W.Ϝ.Y.";

/// VM Seed Bytes: architect's hex identity (0x52 = 'R', 0x59 = 'Y')
pub const VM_SEED_BYTES: &[u8] = &[0x52, 0x59];

